ALTER SEQUENCE public.warehouse_zones_id_seq OWNED BY public.warehouse_zones.id;


--
-- Name: warehouses; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.warehouses (
    id integer NOT NULL,
    tenant_id uuid,
    code character varying(50) NOT NULL,
    name character varying(100) NOT NULL,
    type character varying(20) DEFAULT 'main'::character varying,
    address text,
    city character varying(100),
    province character varying(100),
    phone character varying(30),
    manager character varying(100),
    manager_id integer,
    branch_id uuid,
    capacity numeric(10,2),
    capacity_unit character varying(20) DEFAULT 'sqm'::character varying,
    temperature_min numeric(5,2),
    temperature_max numeric(5,2),
    is_active boolean DEFAULT true,
    status character varying(20) DEFAULT 'active'::character varying,
    operating_hours character varying(50),
    notes text,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now()
);


--
-- Name: warehouses_id_seq; Type: SEQUENCE; Schema: public; Owner: -
