--
-- Name: warning_letters; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.warning_letters (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid,
    employee_id integer NOT NULL,
    warning_type character varying(10) DEFAULT 'SP1'::character varying NOT NULL,
    warning_number character varying(50),
    issue_date date NOT NULL,
    expiry_date date,
    violation_category character varying(50),
    violation_description text NOT NULL,
    evidence text,
    consequences text,
    employee_response text,
    status character varying(20) DEFAULT 'active'::character varying,
    issued_by uuid,
    acknowledged_at timestamp with time zone,
    revoked_at timestamp with time zone,
    revoked_reason text,
    regulation_id uuid,
    previous_warning_id uuid,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now()
);


--
-- Name: wastes; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.wastes (
    id integer NOT NULL,
    waste_number character varying(50) NOT NULL,
    product_id integer,
    product_name character varying(255),
    product_sku character varying(100),
    waste_type character varying(50) NOT NULL,
    quantity numeric(10,2) NOT NULL,
    unit character varying(20) NOT NULL,
    cost_value numeric(15,2) NOT NULL,
    reason text,
    disposal_method character varying(50) NOT NULL,
    clearance_price numeric(15,2),
    waste_date date NOT NULL,
    status character varying(20) DEFAULT 'recorded'::character varying,
    notes text,
    created_by character varying(100),
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP
);


