--
-- Name: webhook_logs; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.webhook_logs (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    webhook_id uuid,
    event character varying(255),
    payload jsonb,
    response_status integer,
    response_body text,
    status character varying(50) DEFAULT 'pending'::character varying,
    attempt integer DEFAULT 1,
    next_retry_at timestamp without time zone,
    error_message text,
    duration_ms integer,
    created_at timestamp without time zone DEFAULT now()
);


--
-- Name: webhooks; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.webhooks (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    tenant_id uuid,
    name character varying(255) NOT NULL,
    url text NOT NULL,
    secret_key character varying(255),
    events text[] DEFAULT '{}'::text[],
    headers jsonb DEFAULT '{}'::jsonb,
    timeout integer DEFAULT 30000,
    retry_count integer DEFAULT 3,
    is_active boolean DEFAULT true,
    created_at timestamp without time zone DEFAULT now(),
    updated_at timestamp without time zone DEFAULT now()
);


--
-- Name: work_shifts; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.work_shifts (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid,
    code character varying(30) NOT NULL,
    name character varying(100) NOT NULL,
    description text,
    shift_type character varying(30) DEFAULT 'regular'::character varying,
    start_time time without time zone NOT NULL,
    end_time time without time zone NOT NULL,
    break_start time without time zone,
    break_end time without time zone,
    break_duration_minutes integer DEFAULT 60,
    is_cross_day boolean DEFAULT false,
    work_hours_per_day numeric(4,2) DEFAULT 8.00,
    color character varying(20) DEFAULT '#3B82F6'::character varying,
    tolerance_late_minutes integer DEFAULT 15,
    tolerance_early_leave_minutes integer DEFAULT 15,
    overtime_after_minutes integer DEFAULT 30,
    applicable_days jsonb DEFAULT '[1, 2, 3, 4, 5]'::jsonb,
    applicable_departments jsonb DEFAULT '[]'::jsonb,
    applicable_branches jsonb DEFAULT '[]'::jsonb,
    max_employees_per_shift integer,
    is_active boolean DEFAULT true,
    sort_order integer DEFAULT 0,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now()
);


--
-- Name: workforce_snapshots; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.workforce_snapshots (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
