    snapshot_date date NOT NULL,
    total_employees integer DEFAULT 0,
    active_employees integer DEFAULT 0,
    new_hires integer DEFAULT 0,
    terminations integer DEFAULT 0,
    turnover_rate numeric(5,2) DEFAULT 0,
    avg_tenure_months numeric(6,1) DEFAULT 0,
    absenteeism_rate numeric(5,2) DEFAULT 0,
    overtime_hours numeric(10,2) DEFAULT 0,
    department_breakdown jsonb DEFAULT '{}'::jsonb,
    branch_breakdown jsonb DEFAULT '{}'::jsonb,
    gender_breakdown jsonb DEFAULT '{}'::jsonb,
    contract_type_breakdown jsonb DEFAULT '{}'::jsonb,
    age_distribution jsonb DEFAULT '{}'::jsonb,
    created_at timestamp with time zone DEFAULT now()
);


