INSERT INTO public.recipes VALUES (1, 'REC-1', 'Nasi Goreng Spesial', 'Nasi goreng dengan telur, ayam, dan sayuran', NULL, 1.00, 'porsi', NULL, 100.00, 10, 15, 25, 24000.00, 0.00, 0.00, 0.00, 0.00, 'easy', 'Main Course', 'draft', 1, 'Panaskan minyak dalam wajan
Tumis bawang merah hingga harum
Masukkan ayam, masak hingga matang
Masukkan nasi, aduk rata
Tambahkan kecap dan bumbu
Buat lubang di tengah, masukkan telur
Aduk semua bahan hingga tercampur rata
Sajikan dengan kerupuk dan acar', NULL, 10, '2026-02-20 02:53:52.242845+07', '2026-02-20 02:53:52.242845+07');
INSERT INTO public.recipes VALUES (2, 'REC-2', 'Soto Ayam', 'Soto ayam kuning dengan kuah gurih', NULL, 1.00, 'porsi', NULL, 100.00, 20, 45, 65, 11000.00, 0.00, 0.00, 0.00, 0.00, 'medium', 'Soup', 'draft', 1, 'Rebus ayam dengan bumbu halus
Angkat ayam, suwir-suwir
Saring kaldu
Siapkan mangkuk saji
Masukkan soun, tauge, ayam
Tuang kuah panas
Beri pelengkap: bawang goreng, seledri, jeruk nipis', NULL, 10, '2026-02-20 02:53:52.242845+07', '2026-02-20 02:53:52.242845+07');
INSERT INTO public.recipes VALUES (3, 'REC-3', 'Ayam Bakar Madu', 'Ayam bakar dengan saus madu pedas manis', NULL, 1.00, 'porsi', NULL, 100.00, 30, 40, 70, 18000.00, 0.00, 0.00, 0.00, 0.00, 'medium', 'Main Course', 'draft', 1, 'Marinasi ayam dengan bumbu halus selama 30 menit
Bakar ayam di atas bara api
Olesi dengan saus madu secara berkala
Bakar hingga matang dan kecoklatan
Sajikan dengan nasi hangat dan lalapan', NULL, 10, '2026-02-20 02:53:52.242845+07', '2026-02-20 02:53:52.242845+07');


